import numpy as np
def validate_1d_f64(a):
    if a.ndim != 1 or a.dtype != np.float64:
        raise ValueError('expected 1d float64')
    print('ok', a.size)
validate_1d_f64(np.array([1.0, 2.0], dtype=np.float64))
try:
    validate_1d_f64(np.array([[1.0]], dtype=np.float64))
except ValueError as e:
    print('| err', e)

